SELECT ST_Equals('LINESTRING(0 0, 10 10)'::geometry,
                 'LINESTRING(10 10, 0 0)'::geometry) AS same_points,
       'LINESTRING(0 0, 10 10)'::geometry = 'LINESTRING(10 10, 0 0)'::geometry AS same_bytes;

SELECT ST_Touches('POLYGON((0 0, 0 10, 10 10, 10 0, 0 0))'::geometry,
                  'POLYGON((10 0, 10 10, 20 10, 20 0, 10 0))'::geometry) AS shares_edge,
       ST_Touches('POINT(0 0)'::geometry, 'POINT(0 0)'::geometry) AS two_points;
